<?php
declare(strict_types=1);
function calendar_http(string $url,string $method='GET',array $headers=[],?string $body=null):array{$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_CUSTOMREQUEST=>$method,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>30,CURLOPT_HTTPHEADER=>$headers,CURLOPT_POSTFIELDS=>$body]);$raw=curl_exec($ch);$status=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);$error=curl_error($ch);curl_close($ch);$data=json_decode((string)$raw,true);if($status<200||$status>=300)throw new RuntimeException('Calendar provider request failed ('.$status.'): '.mb_strimwidth((string)($data['error_description']??$data['error']['message']??$error?:$raw),0,350,'…'));return ['data'=>is_array($data)?$data:[],'raw'=>(string)$raw,'status'=>$status];}
function calendar_connection(int $id,int $userId):array{$q=db()->prepare('SELECT * FROM calendar_connections WHERE id=? AND user_id=?');$q->execute([$id,$userId]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Calendar connection not found');}return $r;}
function calendar_save_oauth(string $provider,array $token,array $profile):void{$uid=(int)user()['id'];$email=(string)($profile['email']??$profile['mail']??$profile['userPrincipalName']??'');$expires=(new DateTimeImmutable())->modify('+'.max(60,(int)($token['expires_in']??3600)).' seconds')->format('Y-m-d H:i:s');$q=db()->prepare("INSERT INTO calendar_connections(user_id,provider,account_email,access_token_enc,refresh_token_enc,expires_at,external_calendar_id,active,sync_status,last_error,last_sync_at) VALUES(?,?,?,?,?,?,'primary',1,'healthy',NULL,NOW()) ON DUPLICATE KEY UPDATE access_token_enc=VALUES(access_token_enc),refresh_token_enc=IF(VALUES(refresh_token_enc)='',refresh_token_enc,VALUES(refresh_token_enc)),expires_at=VALUES(expires_at),active=1,sync_status='healthy',last_error=NULL,last_sync_at=NOW()");$q->execute([$uid,$provider,$email,encrypt_secret((string)$token['access_token']),isset($token['refresh_token'])?encrypt_secret((string)$token['refresh_token']):'',$expires]);audit('connect','calendar_connection',null,['provider'=>$provider,'account'=>$email]);}
function calendar_access_token(array $c):string{$token=decrypt_secret((string)$c['access_token_enc']);if(!$c['expires_at']||new DateTimeImmutable($c['expires_at'])>new DateTimeImmutable('+5 minutes'))return $token;$refresh=decrypt_secret((string)$c['refresh_token_enc']);if($refresh==='')throw new RuntimeException('Calendar authorization expired; reconnect the account.');if($c['provider']==='google'){$body=http_build_query(['client_id'=>app_setting('google_calendar_client_id'),'client_secret'=>decrypt_secret(app_setting('google_calendar_client_secret_enc')),'refresh_token'=>$refresh,'grant_type'=>'refresh_token']);$result=calendar_http('https://oauth2.googleapis.com/token','POST',['Content-Type: application/x-www-form-urlencoded'],$body)['data'];}else{$tenant=app_setting('microsoft_calendar_tenant','common');$body=http_build_query(['client_id'=>app_setting('microsoft_calendar_client_id'),'client_secret'=>decrypt_secret(app_setting('microsoft_calendar_client_secret_enc')),'refresh_token'=>$refresh,'grant_type'=>'refresh_token','scope'=>'offline_access User.Read Calendars.ReadWrite']);$result=calendar_http('https://login.microsoftonline.com/'.rawurlencode($tenant).'/oauth2/v2.0/token','POST',['Content-Type: application/x-www-form-urlencoded'],$body)['data'];}$token=(string)$result['access_token'];$expires=(new DateTimeImmutable())->modify('+'.max(60,(int)($result['expires_in']??3600)).' seconds')->format('Y-m-d H:i:s');db()->prepare('UPDATE calendar_connections SET access_token_enc=?,refresh_token_enc=IF(?=\'\',refresh_token_enc,?),expires_at=?,sync_status=\'healthy\',last_error=NULL,last_sync_at=NOW() WHERE id=?')->execute([encrypt_secret($token),isset($result['refresh_token'])?encrypt_secret($result['refresh_token']):'',isset($result['refresh_token'])?encrypt_secret($result['refresh_token']):'',$expires,$c['id']]);return $token;}
function calendar_busy_ranges(int $userId,DateTimeImmutable $from,DateTimeImmutable $to):array{$q=db()->prepare('SELECT * FROM calendar_connections WHERE user_id=? AND active=1');$q->execute([$userId]);$ranges=[];foreach($q->fetchAll() as $c){try{if($c['provider']==='google'){$token=calendar_access_token($c);$payload=json_encode(['timeMin'=>$from->format(DateTimeInterface::RFC3339),'timeMax'=>$to->format(DateTimeInterface::RFC3339),'items'=>[['id'=>$c['external_calendar_id']?:'primary']]]);$d=calendar_http('https://www.googleapis.com/calendar/v3/freeBusy','POST',['Authorization: Bearer '.$token,'Content-Type: application/json'],$payload)['data'];foreach($d['calendars'][$c['external_calendar_id']?:'primary']['busy']??[] as $b)$ranges[]=[new DateTimeImmutable($b['start']),new DateTimeImmutable($b['end'])];}elseif($c['provider']==='microsoft'){$token=calendar_access_token($c);$payload=json_encode(['schedules'=>[$c['account_email']],'startTime'=>['dateTime'=>$from->format('Y-m-d\TH:i:s'),'timeZone'=>'UTC'],'endTime'=>['dateTime'=>$to->format('Y-m-d\TH:i:s'),'timeZone'=>'UTC'],'availabilityViewInterval'=>15]);$d=calendar_http('https://graph.microsoft.com/v1.0/me/calendar/getSchedule','POST',['Authorization: Bearer '.$token,'Content-Type: application/json'],$payload)['data'];foreach($d['value'][0]['scheduleItems']??[] as $b)$ranges[]=[new DateTimeImmutable($b['start']['dateTime'].' '.$b['start']['timeZone']),new DateTimeImmutable($b['end']['dateTime'].' '.$b['end']['timeZone'])];}else{$auth='Authorization: Basic '.base64_encode($c['account_email'].':'.decrypt_secret((string)$c['access_token_enc']));$xml='<?xml version="1.0"?><c:calendar-query xmlns:d="DAV:" xmlns:c="urn:ietf:params:xml:ns:caldav"><d:prop><c:calendar-data/></d:prop><c:filter><c:comp-filter name="VCALENDAR"><c:comp-filter name="VEVENT"><c:time-range start="'.$from->setTimezone(new DateTimeZone('UTC'))->format('Ymd\THis\Z').'" end="'.$to->setTimezone(new DateTimeZone('UTC'))->format('Ymd\THis\Z').'"/></c:comp-filter></c:comp-filter></c:filter></c:calendar-query>'; $raw=calendar_http((string)$c['external_calendar_id'],'REPORT',[$auth,'Depth: 1','Content-Type: application/xml; charset=utf-8'],$xml)['raw'];preg_match_all('/DTSTART(?:;[^:]*)?:(\d{8}T\d{6}Z?).*?DTEND(?:;[^:]*)?:(\d{8}T\d{6}Z?)/s',$raw,$matches,PREG_SET_ORDER);foreach($matches as $m)$ranges[]=[new DateTimeImmutable($m[1]),new DateTimeImmutable($m[2])];}db()->prepare("UPDATE calendar_connections SET sync_status='healthy',last_error=NULL,last_sync_at=NOW() WHERE id=?")->execute([$c['id']]);}catch(Throwable $e){db()->prepare("UPDATE calendar_connections SET sync_status='error',last_error=? WHERE id=?")->execute([mb_strimwidth($e->getMessage(),0,500),$c['id']]);app_log('error','Calendar busy-time lookup failed',['connection_id'=>$c['id'],'provider'=>$c['provider'],'error'=>$e->getMessage()]);}}return $ranges;}
if($path==='/admin/calendar-integrations'){require_login();if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}if($method==='POST'){verify_csrf();$values=['google_calendar_client_id'=>trim((string)post('google_client_id')),'microsoft_calendar_client_id'=>trim((string)post('microsoft_client_id')),'microsoft_calendar_tenant'=>trim((string)post('microsoft_tenant'))?:'common'];if(post('google_client_secret')!=='')$values['google_calendar_client_secret_enc']=encrypt_secret((string)post('google_client_secret'));if(post('microsoft_client_secret')!=='')$values['microsoft_calendar_client_secret_enc']=encrypt_secret((string)post('microsoft_client_secret'));$save=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($values as $k=>$v)$save->execute([$k,$v]);audit('update','calendar_integration_settings',null,['keys'=>array_keys($values)]);flash('success','Calendar integration settings saved.');redirect('/admin/calendar-integrations');}$s=app_settings();layout('Calendar integrations',function()use($s){?><h1>Calendar integrations</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><h2>Google Calendar OAuth</h2><label>Client ID<input name="google_client_id" value="<?=e($s['google_calendar_client_id'])?>"></label><label>Client secret<input type="password" name="google_client_secret" placeholder="<?=$s['google_calendar_client_secret_enc']?'Stored — leave blank to keep':''?>"></label><p class="muted">Redirect URI: <?=e(rtrim((string)config('url'),'/').'/calendar/oauth/google/callback')?></p><h2>Microsoft 365 OAuth</h2><label>Application (client) ID<input name="microsoft_client_id" value="<?=e($s['microsoft_calendar_client_id'])?>"></label><label>Client secret<input type="password" name="microsoft_client_secret" placeholder="<?=$s['microsoft_calendar_client_secret_enc']?'Stored — leave blank to keep':''?>"></label><label>Tenant<input name="microsoft_tenant" value="<?=e($s['microsoft_calendar_tenant'])?>"></label><p class="muted">Redirect URI: <?=e(rtrim((string)config('url'),'/').'/calendar/oauth/microsoft/callback')?></p><button>Save integrations</button></form><?php });exit;}
if($path==='/settings/calendars'){require_login();$uid=(int)user()['id'];if($method==='POST'){verify_csrf();$action=(string)post('action');if($action==='caldav'){try{$url=trim((string)post('caldav_url'));$username=trim((string)post('caldav_username'));$password=(string)post('caldav_password');calendar_http($url,'PROPFIND',['Authorization: Basic '.base64_encode($username.':'.$password),'Depth: 0'],'<?xml version="1.0"?><d:propfind xmlns:d="DAV:"><d:prop><d:displayname/></d:prop></d:propfind>');db()->prepare("INSERT INTO calendar_connections(user_id,provider,account_email,access_token_enc,external_calendar_id,active,sync_status,last_sync_at) VALUES(?,'caldav',?,?,?,1,'healthy',NOW()) ON DUPLICATE KEY UPDATE access_token_enc=VALUES(access_token_enc),external_calendar_id=VALUES(external_calendar_id),active=1,sync_status='healthy',last_error=NULL,last_sync_at=NOW()")->execute([$uid,$username,encrypt_secret($password),$url]);flash('success','CalDAV calendar connected.');}catch(Throwable $e){flash('error',$e->getMessage());}}elseif($action==='disconnect'){db()->prepare('UPDATE calendar_connections SET active=0 WHERE id=? AND user_id=?')->execute([(int)post('connection_id'),$uid]);flash('success','Calendar disconnected.');}redirect('/settings/calendars');}$q=db()->prepare('SELECT id,provider,account_email,external_calendar_id,sync_status,last_error,last_sync_at,active FROM calendar_connections WHERE user_id=? ORDER BY provider,account_email');$q->execute([$uid]);$rows=$q->fetchAll();layout('Connected calendars',function()use($rows){?><div class="actions"><h1 style="margin:0">Connected calendars</h1><span class="spacer"></span><?php if(app_setting('google_calendar_client_id')&&app_setting('google_calendar_client_secret_enc')):?><a class="btn" href="/calendar/oauth/google">Connect Google</a><?php endif?><?php if(app_setting('microsoft_calendar_client_id')&&app_setting('microsoft_calendar_client_secret_enc')):?><a class="btn" href="/calendar/oauth/microsoft">Connect Microsoft 365</a><?php endif?></div><div class="card"><table><thead><tr><th>Provider</th><th>Account</th><th>Health</th><th>Last checked</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e(ucfirst($r['provider']))?></td><td><?=e($r['account_email'])?></td><td><?=e($r['sync_status'])?><?php if($r['last_error']):?><br><span class="danger-text"><?=e($r['last_error'])?></span><?php endif?></td><td><?=e($r['last_sync_at']?:'Never')?></td><td><?php if($r['active']):?><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="disconnect"><input type="hidden" name="connection_id" value="<?=$r['id']?>"><button class="danger compact">Disconnect</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="caldav"><h2>Connect CalDAV</h2><label>Calendar URL<input type="url" name="caldav_url" required></label><label>Username<input name="caldav_username" required></label><label>Password or app password<input type="password" name="caldav_password" required></label><button>Connect CalDAV</button></form><?php });exit;}
if(preg_match('#^/calendar/oauth/(google|microsoft)$#',$path,$m)){require_login();$provider=$m[1];$state=bin2hex(random_bytes(24));$_SESSION['calendar_oauth_state']=['value'=>$state,'provider'=>$provider,'time'=>time()];$redirect=rtrim((string)config('url'),'/').'/calendar/oauth/'.$provider.'/callback';if($provider==='google'){$params=['client_id'=>app_setting('google_calendar_client_id'),'redirect_uri'=>$redirect,'response_type'=>'code','scope'=>'openid email https://www.googleapis.com/auth/calendar','access_type'=>'offline','prompt'=>'consent','state'=>$state];redirect('https://accounts.google.com/o/oauth2/v2/auth?'.http_build_query($params));}$tenant=app_setting('microsoft_calendar_tenant','common');$params=['client_id'=>app_setting('microsoft_calendar_client_id'),'redirect_uri'=>$redirect,'response_type'=>'code','scope'=>'openid email profile offline_access User.Read Calendars.ReadWrite','state'=>$state];redirect('https://login.microsoftonline.com/'.rawurlencode($tenant).'/oauth2/v2.0/authorize?'.http_build_query($params));}
if(preg_match('#^/calendar/oauth/(google|microsoft)/callback$#',$path,$m)){require_login();$provider=$m[1];$saved=$_SESSION['calendar_oauth_state']??[];unset($_SESSION['calendar_oauth_state']);if(!hash_equals((string)($saved['value']??''),(string)($_GET['state']??''))||($saved['provider']??'')!==$provider||time()-(int)($saved['time']??0)>900){http_response_code(400);exit('Invalid or expired OAuth state.');}if(isset($_GET['error'])){flash('error','Calendar authorization was declined.');redirect('/settings/calendars');}$redirect=rtrim((string)config('url'),'/').'/calendar/oauth/'.$provider.'/callback';try{if($provider==='google'){$body=http_build_query(['client_id'=>app_setting('google_calendar_client_id'),'client_secret'=>decrypt_secret(app_setting('google_calendar_client_secret_enc')),'code'=>(string)$_GET['code'],'grant_type'=>'authorization_code','redirect_uri'=>$redirect]);$token=calendar_http('https://oauth2.googleapis.com/token','POST',['Content-Type: application/x-www-form-urlencoded'],$body)['data'];$profile=calendar_http('https://openidconnect.googleapis.com/v1/userinfo','GET',['Authorization: Bearer '.$token['access_token']])['data'];}else{$tenant=app_setting('microsoft_calendar_tenant','common');$body=http_build_query(['client_id'=>app_setting('microsoft_calendar_client_id'),'client_secret'=>decrypt_secret(app_setting('microsoft_calendar_client_secret_enc')),'code'=>(string)$_GET['code'],'grant_type'=>'authorization_code','redirect_uri'=>$redirect,'scope'=>'openid email profile offline_access User.Read Calendars.ReadWrite']);$token=calendar_http('https://login.microsoftonline.com/'.rawurlencode($tenant).'/oauth2/v2.0/token','POST',['Content-Type: application/x-www-form-urlencoded'],$body)['data'];$profile=calendar_http('https://graph.microsoft.com/v1.0/me','GET',['Authorization: Bearer '.$token['access_token']])['data'];}calendar_save_oauth($provider,$token,$profile);flash('success',ucfirst($provider).' Calendar connected.');}catch(Throwable $e){flash('error',$e->getMessage());}redirect('/settings/calendars');}
